140→            has_liked: false,
141→            has_bookmarked: false,
142→            user_reaction: null
143→        }));
144→    }
145→
146→    const journalIds = journals.map((journal) => journal.id);
147→
148→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
149→        supabase
150→            .from('likes')
151→            .select('journal_id')
152→            .in('journal_id', journalIds)
153→            .eq('user_id', userId),
154→        supabase
155→            .from('bookmarks')
156→            .select('journal_id')
157→            .in('journal_id', journalIds)
158→            .eq('user_id', userId),
159→        supabase
160→            .from('reactions')
