162→            .in('journal_id', journalIds)
163→            .eq('user_id', userId)
164→    ]);
165→
166→    const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
167→    const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
