172→        throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'};
173→    }
174→
175→    const userHasLikedSet = new Set(userLikesResult?.map((journal) => journal.journal_id) || []);
176→    const userHasBookmarkedSet = new Set(userBookmarksResult?.map((journal) => journal.journal_id) || []);
177→    const userReactionMap = new Map((userReactionsResult || []).map((r) => [r.journal_id, r.reaction_type]));
178→
179→    return journals.map((journal) => ({
180→        ...journal,
181→        has_liked: userHasLikedSet.has(journal.id),
182→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
183→        user_reaction: userReactionMap.get(journal.id) || null
184→    }));
